"use strict";async function inject(t,e){const n=document.getElementById(t);if(!n)return;const a=await fetch(e);a.ok?n.outerHTML=await a.text():console.error(`layout.js: failed to load ${e}`)}document.addEventListener("DOMContentLoaded",()=>{Promise.all([inject("site-header","partials/header.html"),inject("site-footer","partials/footer.html"),inject("partner-banner","partials/partner-banner.html")])});